22	// generateSessionID returns a unique session identifier for a new Execute.
23	func generateSessionID() string {
24		return fmt.Sprintf("svc-%d", time.Now().UnixNano())
25	}
26	
27	// Execute runs an agent task in-process; emits Events on the returned
28	// channel until the task terminates (channel closes). The final event
29	// (type=final) carries status, usage, cost, session-log path, and the
30	// resolved fallback chain that fired.
31	//
32	// See CONTRACT-003 §"Behaviors the contract guarantees" for the full
33	// behavior contract this method honors:
34	//   - Orphan-model validation (Status=failed when Model unknown)
35	//   - Provider-deadline wrapping (Timeout + IdleTimeout + ProviderTimeout)
36	//   - StallPolicy enforcement (stall event before final)
37	//   - Route-reason attribution (routing_decision start, routing_actual final)
38	//   - OS-level subprocess cleanup on ctx.Done()
39	//   - Metadata bidirectional echo (events + session log)
40	//   - SessionLogDir per-request override
41	//
42	// Routing: under-specified requests (no Harness) are dispatched through
43	// internal/routing.Resolve via ResolveRoute. Callers can run with bare
44	// Profile/ModelRef/Model/Provider — the engine picks. NativeProvider must
45	// still be supplied for the native path until provider construction lands
46	// in a follow-up.
47	func (s *service) Execute(ctx context.Context, req ServiceExecuteRequest) (<-chan ServiceEvent, error) {
48		// Boundary validation: reject unknown CachePolicy values before any
49		// session state is opened or events are emitted. Beads C/D consume this
50		// field; an unknown value is a caller programming error.
51		if err := ValidateCachePolicy(req.CachePolicy); err != nil {
52			return nil, err
53		}
54		if err := ValidatePowerBounds(req.MinPower, req.MaxPower); err != nil {
55			return nil, err
56		}
57		if err := ValidateRole(req.Role); err != nil {
58			return nil, err
59		}
60		if err := ValidateCorrelationID(req.CorrelationID); err != nil {
61			return nil, err
62		}
63	
64		// Generate a session ID and register it in the hub so TailSessionLog
65		// callers can subscribe before or during execution.
66		sessionID := generateSessionID()
67		fanout := s.executeEventFanout()
68		fanout.openSession(sessionID)
69	
70		outer := make(chan ServiceEvent, 64)
71	
72		// ADR-006 §3/§4: capture the override context (user pin + unconstrained
73		// auto decision) before route resolution so we can fire the matching
74		// override / rejected_override event regardless of which path the route
75		// resolution takes.
76		overrideCtx := s.buildOverrideContext(ctx, req)
77	
78		// ADR-006 §5: record this request into the routing-quality store so
79		// auto_acceptance_rate / override_disagreement_rate / class_breakdown
80		// reflect both overridden and non-overridden traffic. The recorded
81		// override payload carries no outcome — outcome aggregation for live
82		// requests is best-effort and lives in session logs once that
83		// persistence path lands.
84		s.recordRoutingQualityForRequest(overrideCtx)
85	
86		// Resolve the route.
87		decision, err := s.executeRouteResolver().resolveExecuteRoute(req)
88		if err != nil {
89			// NoViableProviderForNow is a transient quota signal — DDx
90			// callers pause their drain loop on RetryAfter and resume.
91			// Surface it directly (not via the fatal-final channel) so the
92			// typed error reaches errors.As without log scraping.
93			var quotaErr *NoViableProviderForNow
94			if errors.As(err, &quotaErr) {
95				fanout.closeSession(sessionID, ServiceEvent{})
96				return nil, err
97			}
98			if isExplicitPinError(err) {
99				// Emit a rejected_override event (no outcome) when the pin
100				// fails pre-dispatch. Surface the typed error wrapped with
101				// the rejected_override payload so callers that errors.As
102				// the typed pin error still get it; callers wanting the
103				// telemetry can extract via AsRejectedOverride.
104				pinErr := err
105				if overrideCtx != nil {
106					if rejectedEv, payload, ok := makeRejectedOverrideEvent(overrideCtx, sessionID, pinErr, req.Metadata); ok {
107						fanout.broadcastEvent(sessionID, rejectedEv)
108						// Persist the rejected_override to the session log so
109						// UsageReport's windowed scan (which sources from
110						// session logs, not the in-memory ring) sees this
111						// rejection. The pin failed pre-dispatch, so no
112						// runExecute will open a log for this session — open
113						// one briefly here, write session.start + the rejected
114						// payload, and close.
115						s.persistRejectedOverride(req, sessionID, payload)
116						pinErr = &ErrRejectedOverride{Inner: err, Event: payload}
117					}
118				}
119				fanout.closeSession(sessionID, ServiceEvent{})
120				return nil, pinErr
121			}
122			// Still return a channel that yields a single failed final event so
123			// downstream consumers don't have to special-case the error path.
124			// Also close the hub session so TailSessionLog subscribers unblock.
125			go func() {
126				emitFatalFinal(outer, req.Metadata, "failed", err.Error())
127				// Drain outer to get the final event and forward to hub.
128				// emitFatalFinal closes outer; read the single event from it.
129			}()
130			// We can't easily intercept emitFatalFinal here, so close the hub
131			// session with an empty final immediately — callers on TailSessionLog
132			// for a failed-route session get an empty close.
133			go func() {
134				// Wait briefly for emitFatalFinal to write.
135				time.Sleep(10 * time.Millisecond)
136				fanout.closeSession(sessionID, ServiceEvent{})
137			}()
138			return outer, nil
139		}
140	
141		// Metadata seam: every event we emit echoes req.Metadata.
142		meta := req.Metadata
143	
144		// Wrap the inner channel through the hub so every event is broadcast to
145		// TailSessionLog subscribers. The fan-out goroutine owns outer's close
146		// and is responsible for inserting the override event (if any) immediately
147		// before the final event per ADR-006 §7.
148		inner := fanout.wrapExecuteWithHub(sessionID, outer, overrideCtx, meta)
149	
150		// Emit start-of-execution routing_decision so consumers know the picked
151		// chain before any real work fires. The actual chain (post-fallback) is
152		// stamped onto the final event's RoutingActual field.
153		go s.runExecute(ctx, req, *decision, meta, inner, sessionID, overrideCtx)
154		return outer, nil
155	}
