157	// resolveExecuteRoute reduces the request to a concrete RouteDecision.
158	// The request is dispatched through the routing engine
159	// (internal/routing.Resolve) when under-specified (Harness == ""), or when
160	// Harness is set but Model is empty and routing inputs (Profile or MinPower)
161	// are present (engine runs within the harness's eligible models). When Harness
162	// is set and Model is also set, the decision is accepted verbatim.
163	func (s *service) resolveExecuteRoute(req ServiceExecuteRequest) (*RouteDecision, error) {
164		// If Harness is omitted, route through the engine. The engine defaults to
165		// local-first and auto-selects from configured endpoints when no other
166		// constraints are specified — an empty request is valid if providers exist.
167		if req.Harness == "" {
168			return s.resolveExecuteRouteWithEngine(req)
169		}
170		canonical := harnesses.ResolveHarnessAlias(req.Harness)
171		if !s.registry.Has(canonical) {
172			return nil, fmt.Errorf("unknown harness %q", req.Harness)
173		}
174		cfg, _ := s.registry.Get(canonical)
175	
176		// Run per-field validators first so callers get the most specific error.
177		// Empty-model routing checks run after these, right before model resolution.
178		if err := validateExplicitHarnessProfile(canonical, cfg, req.Profile); err != nil {
179			return nil, err
180		}
181		if err := validateExplicitProvider(s.opts.ServiceConfig, cfg, req.Provider); err != nil {
182			return nil, err
183		}
184		if err := validateExplicitHarnessModel(canonical, cfg, req.Model, req.Provider); err != nil {
185			return nil, err
186		}
187		if err := validateExplicitHarnessReasoning(canonical, cfg, req.Reasoning); err != nil {
188			return nil, err
189		}
190		if err := validateExplicitHarnessQuota(canonical, cfg); err != nil {
191			return nil, err
192		}
193	
194		// Empty-model routing: only applies to subprocess harnesses with concrete
195		// model semantics. TestOnly (virtual/script), HTTP-provider (openrouter/
196		// lmstudio/etc.), and "fiz" harnesses skip this block — they either use
197		// DefaultModel directly or have provider-side model semantics.
198		if !cfg.TestOnly && !cfg.IsHTTPProvider && canonical != "fiz" && req.Model == "" {
199			if req.Profile == "" && req.MinPower == 0 {
200				// Under-specified: no model, no routing inputs → silent empty model
201				// avoided by failing early with a clear diagnostic.
202				return nil, fmt.Errorf("under-specified routing for harness=%q: "+
203					"supply --model, --profile, or --min-power", canonical)
204			}
205			// Profile or MinPower present: run the routing engine within the
206			// harness's eligible models. Class 2 harnesses (AutoRoutingEligible=false:
207			// gemini, opencode, pi) require an explicit --model.
208			if !cfg.AutoRoutingEligible {
209				return nil, fmt.Errorf("no auto-resolution available for harness=%q: "+
210					"harness does not support auto-routing; supply an explicit --model", canonical)
211			}
212			return s.resolveExecuteRouteWithEngine(req)
213		}
214	
215		resolvedModel := resolveSubprocessModelAlias(canonical, req.Model)
216		decision := &RouteDecision{
217			Harness:  canonical,
218			Provider: req.Provider,
219			Model:    resolvedModel,
220			Reason:   "explicit",
221			Power:    catalogPowerForModel(serviceRoutingCatalog(), resolvedModel),
222		}
223		if decision.Endpoint == "" {
224			_, endpoint, _ := splitEndpointProviderRef(decision.Provider)
225			decision.Endpoint = endpoint
226		}
227		return decision, nil
228	}
