230	func validateExplicitHarnessQuota(name string, cfg harnesses.HarnessConfig) error {
231		if !cfg.IsSubscription {
232			return nil
233		}
234		now := time.Now()
235		qs, ok := subscriptionQuotaForHarness(name, now)
236		if !ok || !qs.Present || !qs.Fresh || qs.OK {
237			return nil
238		}
239		return explicitQuotaUnavailable(name, qs.Windows, now)
240	}
241	
242	func explicitQuotaUnavailable(name string, windows []harnesses.QuotaWindow, now time.Time) error {
243		retryAfter := earliestQuotaResetAfter(windows, now)
244		if retryAfter.IsZero() {
245			retryAfter = now.Add(defaultQuotaRecoveryFallbackInterval)
246		}
247		return &NoViableProviderForNow{
248			RetryAfter:         retryAfter,
249			ExhaustedProviders: []string{name},
250		}
251	}
252	
253	func earliestQuotaResetAfter(windows []harnesses.QuotaWindow, now time.Time) time.Time {
254		var earliest time.Time
255		for _, window := range windows {
256			if window.ResetsAtUnix <= 0 {
257				continue
258			}
259			reset := time.Unix(window.ResetsAtUnix, 0)
260			if !reset.After(now) {
261				continue
262			}
263			if earliest.IsZero() || reset.Before(earliest) {
264				earliest = reset
265			}
266		}
267		return earliest
268	}
