270	func validateExplicitHarnessProfile(name string, cfg harnesses.HarnessConfig, profile string) error {
271		constraint, ok := explicitProfileConstraint(profile)
272		if !ok {
273			return nil
274		}
275		switch constraint {
276		case routing.ProviderPreferenceLocalOnly:
277			if !cfg.IsLocal {
278				return &ErrProfilePinConflict{
279					Profile:           profile,
280					ConflictingPin:    "Harness=" + name,
281					ProfileConstraint: constraint,
282				}
283			}
284		case routing.ProviderPreferenceSubscriptionOnly:
285			if !cfg.IsSubscription {
286				return &ErrProfilePinConflict{
287					Profile:           profile,
288					ConflictingPin:    "Harness=" + name,
289					ProfileConstraint: constraint,
290				}
291			}
292		}
293		return nil
294	}
295	
296	func explicitProfileConstraint(profile string) (string, bool) {
297		switch profile {
298		case "local", "offline", "air-gapped":
299			return routing.ProviderPreferenceLocalOnly, true
300		case "smart", "code-smart", "code-high":
301			return routing.ProviderPreferenceSubscriptionOnly, true
302		default:
303			return "", false
304		}
305	}
