307	func isExplicitPinError(err error) bool {
308		var modelConstraintAmbiguous *ErrModelConstraintAmbiguous
309		if errors.As(err, &modelConstraintAmbiguous) {
310			return true
311		}
312		var modelConstraintNoMatch *ErrModelConstraintNoMatch
313		if errors.As(err, &modelConstraintNoMatch) {
314			return true
315		}
316		var modelErr *ErrHarnessModelIncompatible
317		if errors.As(err, &modelErr) {
318			return true
319		}
320		var profileErr *ErrProfilePinConflict
321		if errors.As(err, &profileErr) {
322			return true
323		}
324		var providerErr *ErrUnknownProvider
325		return errors.As(err, &providerErr)
326	}
