328	// validateExplicitProvider rejects pre-dispatch when the caller pinned a
329	// provider name that the service configuration does not recognize. Returns
330	// nil when no provider was pinned, when no ServiceConfig is configured (no
331	// provider catalog to validate against), when the provider name is known,
332	// or when the harness is test-only / does not consume Provider (virtual,
333	// script, etc. have no real provider lookup).
334	func validateExplicitProvider(sc ServiceConfig, cfg harnesses.HarnessConfig, provider string) error {
335		if provider == "" || sc == nil {
336			return nil
337		}
338		if cfg.TestOnly {
339			return nil
340		}
341		lookup := provider
342		if base, _, ok := splitEndpointProviderRef(provider); ok {
343			lookup = base
344		}
345		if _, ok := sc.Provider(lookup); ok {
346			return nil
347		}
348		known := sc.ProviderNames()
349		return &ErrUnknownProvider{Provider: provider, KnownProviders: append([]string(nil), known...)}
350	}
