352	func validateExplicitHarnessModel(name string, cfg harnesses.HarnessConfig, model, provider string) error {
353		if model == "" || cfg.TestOnly || cfg.IsHTTPProvider || name == "fiz" {
354			return nil
355		}
356		if modelSupportedForHarness(name, cfg, model, provider) {
357			return nil
358		}
359		supportedModels := subprocessHarnessModelIDs(name, cfg)
360		return &ErrHarnessModelIncompatible{
361			Harness:         name,
362			Model:           model,
363			SupportedModels: append([]string(nil), supportedModels...),
364		}
365	}
366	
367	func modelSupportedForHarness(name string, cfg harnesses.HarnessConfig, model, provider string) bool {
368		for _, known := range subprocessHarnessModelIDs(name, cfg) {
369			if model == known {
370				return true
371			}
372		}
373		switch name {
374		case "codex":
375			return strings.HasPrefix(model, "gpt-")
376		case "claude":
377			return strings.HasPrefix(model, "claude-")
378		case "pi":
379			// Pi can route to non-Gemini backends (lmstudio, omlx, etc.) when a
380			// provider is pinned. The pi CLI owns per-provider model validation
381			// in that case, so the agent-side gate trusts the provider pin and
382			// defers concrete model-ID checks to pi --list-models / pi itself.
383			return provider != ""
384		case "opencode":
385			// OpenCode can route to configured provider/model pairs when the
386			// provider is pinned; the generated opencode config and CLI own the
387			// concrete model validation in that case.
388			return provider != ""
389		default:
390			return len(cfg.Models) == 0
391		}
392	}
