394	func validateExplicitHarnessReasoning(name string, cfg harnesses.HarnessConfig, value Reasoning) error {
395		if cfg.TestOnly {
396			return nil
397		}
398		if len(cfg.ReasoningLevels) == 0 && cfg.MaxReasoningTokens <= 0 {
399			return nil
400		}
401		policy, err := reasoning.ParseString(string(value))
402		if err != nil {
403			return fmt.Errorf("unsupported reasoning %q for harness %q: %w", value, name, err)
404		}
405		switch policy.Kind {
406		case reasoning.KindUnset, reasoning.KindAuto, reasoning.KindOff:
407			return nil
408		case reasoning.KindTokens:
409			if cfg.MaxReasoningTokens <= 0 {
410				return fmt.Errorf("unsupported reasoning %q for harness %q; token budgets are not supported", value, name)
411			}
412			if policy.Tokens > cfg.MaxReasoningTokens {
413				return fmt.Errorf("unsupported reasoning %q for harness %q; max token budget is %d", value, name, cfg.MaxReasoningTokens)
414			}
415			return nil
416		case reasoning.KindNamed:
417			for _, supported := range cfg.ReasoningLevels {
418				if string(policy.Value) == supported {
419					return nil
420				}
421			}
422			return fmt.Errorf("unsupported reasoning %q for harness %q; supported reasoning: %s", value, name, strings.Join(cfg.ReasoningLevels, ", "))
423		default:
424			return fmt.Errorf("unsupported reasoning %q for harness %q", value, name)
425		}
426	}
