435	// runExecute is the per-Execute goroutine. It owns the channel close path
436	// and the final event emit. All termination paths funnel through emitFinal
437	// so the channel always sees a final event before close.
438	func (s *service) runExecute(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, sessionID string, overrideCtx *overrideContext) {
439		defer close(out)
440	
441		start := time.Now()
442		var seq atomic.Int64
443	
444		// Open the service-owned session log writer and guarantee a terminal
445		// session.end record plus a clean file close even on unexpected exits.
446		// CONTRACT-003 makes session-log lifecycle a service responsibility; the
447		// per-path finalizeAndEmit calls below feed writeEnd in lock-step with
448		// the public final event.
449		sl := s.executeSessionLogOpener().openSessionLog(req, decision, sessionID)
450		if overrideCtx != nil {
451			sl.override = overrideCtx
452		}
453		defer func() {
454			if !sl.endWritten() {
455				sl.writeEnd(req, meta, harnesses.FinalData{
456					Status:     "cancelled",
457					Error:      "session ended without final event",
458					DurationMS: time.Since(start).Milliseconds(),
459					RoutingActual: &harnesses.RoutingActual{
460						Harness:  decision.Harness,
461						Provider: decision.Provider,
462						Model:    decision.Model,
463					},
464				})
465			}
466			sl.close()
467		}()
468	
469		// Wall-clock cap.
470		runCtx := ctx
471		if req.Timeout > 0 {
472			var cancel context.CancelFunc
473			runCtx, cancel = context.WithTimeout(ctx, req.Timeout)
474			defer cancel()
475		}
476	
477		// Emit routing_decision start event. Include session_id so callers can
478		// extract it and pass to TailSessionLog. Per CONTRACT-003 the
479		// top-level Role + CorrelationID are echoed into routing_decision
480		// event Metadata (top-level wins over caller Metadata for these
481		// reserved keys).
482		routingMeta := metaWithRoleAndCorrelation(meta, req.Role, req.CorrelationID)
483		emitJSON(out, &seq, harnesses.EventTypeRoutingDecision, routingMeta, ServiceRoutingDecisionData{
484			Harness:        decision.Harness,
485			Provider:       decision.Provider,
486			Endpoint:       decision.Endpoint,
487			ServerInstance: decision.ServerInstance,
488			Model:          decision.Model,
489			Reason:         decision.Reason,
490			Sticky: ServiceRoutingStickyState{
491				KeyPresent:     decision.Sticky.KeyPresent,
492				Assignment:     decision.Sticky.Assignment,
493				ServerInstance: decision.Sticky.ServerInstance,
494				Reason:         decision.Sticky.Reason,
495				Bonus:          decision.Sticky.Bonus,
496			},
497			Utilization: ServiceRoutingUtilizationState{
498				Source:         decision.Utilization.Source,
499				Freshness:      decision.Utilization.Freshness,
500				ActiveRequests: decision.Utilization.ActiveRequests,
501				QueuedRequests: decision.Utilization.QueuedRequests,
502				MaxConcurrency: decision.Utilization.MaxConcurrency,
503				CachePressure:  decision.Utilization.CachePressure,
504				ObservedAt:     decision.Utilization.ObservedAt,
505			},
506			RequestedHarness: req.Harness,
507			HarnessSource:    harnessSource(req),
508			SessionID:        sessionID,
509			Candidates:       routingDecisionEventCandidates(decision.Candidates),
510		})
511		emitProgress(out, &seq, sl, sessionID, meta, routeProgressData(decision))
512	
513		s.executeRunnerInvoker().dispatchExecuteRun(runCtx, executeRunContext{
514			req:      req,
515			decision: decision,
516			meta:     meta,
517			out:      out,
518			seq:      &seq,
519			start:    start,
520			sl:       sl,
521			session:  sessionID,
522		})
523	}
