525	func (s *service) runVirtual(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string) {
526		progress := newSubprocessProgressState(req)
527		emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
528		result := serviceimpl.RunVirtual(ctx, executeRunnerRequest(req, decision, meta, start))
529		final := result.Final
530		if result.EmitText {
531			emitJSONRaw(out, seq, harnesses.EventTypeTextDelta, meta, harnesses.TextDeltaData{Text: result.Text})
532		}
533		if progressFinal := progress.noteResponseComplete(final); progressFinal != nil {
534			emitProgress(out, seq, sl, sessionID, meta, *progressFinal)
535		}
536		finalizeAndEmit(out, seq, meta, req, sl, final)
537	}
