540		progress := newSubprocessProgressState(req)
541		emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
542		result := serviceimpl.RunScript(ctx, executeRunnerRequest(req, decision, meta, start))
543		final := result.Final
544		if result.EmitText {
545			emitJSONRaw(out, seq, harnesses.EventTypeTextDelta, meta, harnesses.TextDeltaData{Text: result.Text})
546		}
547		if progressFinal := progress.noteResponseComplete(final); progressFinal != nil {
548			emitProgress(out, seq, sl, sessionID, meta, *progressFinal)
549		}
550		finalizeAndEmit(out, seq, meta, req, sl, final)
