554		return serviceimpl.ExecuteRunnerRequest{
555			Prompt:   req.Prompt,
556			Metadata: meta,
557			Decision: serviceimpl.ExecuteRunnerDecision{
558				Harness:        decision.Harness,
559				Provider:       decision.Provider,
560				ServerInstance: decision.ServerInstance,
