574	// runNative drives the in-process agent loop (loop.go's Run). The provider
575	// is wrapped so per-HTTP timeouts fire independently of the request wall-clock
576	// cap.
577	func (s *service) runNative(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string) {
578		progress := newNativeProgressState()
579		observeAgentEvent := func(ev agentcore.Event) {
580			sl.writeEvent(ev)
581			switch ev.Type {
582			case agentcore.EventLLMRequest:
583				var payload nativeLLMRequestPayload
584				if err := json.Unmarshal(ev.Data, &payload); err == nil {
585					emitProgress(out, seq, sl, sessionID, meta, progress.noteRequest(payload))
586				}
587			case agentcore.EventLLMResponse:
588				var payload nativeLLMResponsePayload
589				if err := json.Unmarshal(ev.Data, &payload); err == nil {
590					emitProgress(out, seq, sl, sessionID, meta, progress.noteResponse(payload))
591				}
592			case agentcore.EventToolCall:
593				var payload nativeToolCallPayload
594				_ = json.Unmarshal(ev.Data, &payload)
595				toolName := payload.Tool
596				input := payload.Input
597				if input == nil {
598					if rawIn, err := json.Marshal(map[string]any{"tool": toolName}); err == nil {
599						input = rawIn
600					}
601				}
602				callID := fmt.Sprintf("call-%d", ev.Seq)
603				_, completeProgress := progress.noteToolCall(callID, payload)
604				emitJSONRaw(out, seq, harnesses.EventTypeToolCall, meta, harnesses.ToolCallData{
605					ID:    callID,
606					Name:  toolName,
607					Input: input,
608				})
609				emitJSONRaw(out, seq, harnesses.EventTypeToolResult, meta, harnesses.ToolResultData{
610					ID:         callID,
611					Output:     payload.Output,
612					Error:      payload.Error,
613					DurationMS: payload.DurationMS,
614				})
615				emitProgress(out, seq, sl, sessionID, meta, completeProgress)
616			case agentcore.EventCompactionEnd:
617				var payload nativeCompactionPayload
618				_ = json.Unmarshal(ev.Data, &payload)
619				emitJSONRaw(out, seq, harnesses.EventTypeCompaction, meta, map[string]any{
620					"messages_before": payload.MessagesBefore,
621					"messages_after":  payload.MessagesAfter,
622					"tokens_freed":    payload.TokensBefore - payload.TokensAfter,
623				})
624				compactionProgress, contextProgress := progress.noteCompaction(payload)
625				emitProgress(out, seq, sl, sessionID, meta, compactionProgress)
626				emitProgress(out, seq, sl, sessionID, meta, contextProgress)
627			}
628		}
629	
630		var stallMaxReadOnlyIterations *int
631		if req.StallPolicy != nil {
632			stallMaxReadOnlyIterations = &req.StallPolicy.MaxReadOnlyToolIterations
633		}
634		serviceimpl.RunNative(ctx, serviceimpl.NativeRequest{
635			Prompt:                    req.Prompt,
636			SystemPrompt:              req.SystemPrompt,
637			Model:                     req.Model,
638			Provider:                  req.Provider,
639			Harness:                   req.Harness,
640			WorkDir:                   req.WorkDir,
641			Temperature:               req.Temperature,
642			TopP:                      req.TopP,
643			TopK:                      req.TopK,
644			MinP:                      req.MinP,
645			RepetitionPenalty:         req.RepetitionPenalty,
646			Seed:                      req.Seed,
647			SamplingSource:            req.SamplingSource,
648			Reasoning:                 effectiveReasoning(req.Reasoning),
649			NoStream:                  req.NoStream,
650			Permissions:               req.Permissions,
651			Tools:                     nativeToolsForRequest(req),
652			ToolPreset:                req.ToolPreset,
653			PlanningMode:              req.PlanningMode,
654			MaxIterations:             req.MaxIterations,
655			MaxTokens:                 req.MaxTokens,
656			ReasoningByteLimit:        req.ReasoningByteLimit,
657			ProviderTimeout:           req.ProviderTimeout,
658			Timeout:                   req.Timeout,
659			CachePolicy:               req.CachePolicy,
660			StallMaxReadOnlyIteration: stallMaxReadOnlyIterations,
661			Metadata:                  meta,
662			Decision:                  nativeDecision(decision),
663			Started:                   start,
664			SessionID:                 sessionID,
665		}, serviceimpl.NativeCallbacks{
666			ResolveProvider: func(nreq serviceimpl.NativeProviderRequest) serviceimpl.NativeProviderResolution {
667				resolved := s.resolveNativeProvider(ServiceExecuteRequest{
668					Provider: nreq.Provider,
669					Harness:  nreq.Harness,
670					Model:    nreq.Model,
671				})
672				return serviceimpl.NativeProviderResolution{
673					Provider: resolved.Provider,
674					Name:     resolved.Name,
675					Model:    resolved.Entry.Model,
676				}
677			},
678			ProviderNotConfiguredError: func(nreq serviceimpl.NativeProviderRequest, ndecision serviceimpl.NativeDecision) string {
679				return s.nativeProviderNotConfiguredError(ServiceExecuteRequest{
680					Provider: nreq.Provider,
681					Harness:  nreq.Harness,
682					Model:    nreq.Model,
683				}, routeDecision(ndecision))
684			},
685			Compactor: func(model string) agentcore.Compactor {
686				return newServiceCompactor(req, model)
687			},
688			ObserveAgentEvent: observeAgentEvent,
689			EmitEvent: func(t harnesses.EventType, payload any) {
690				emitJSONRaw(out, seq, t, meta, payload)
691			},
692			BeforeFinal: func(final harnesses.FinalData) {
693				if progressFinal := progress.noteFinal(final); progressFinal != nil {
694					emitProgress(out, seq, sl, sessionID, meta, *progressFinal)
695				}
696			},
697			Finalize: func(final harnesses.FinalData) {
698				finalizeAndEmit(out, seq, meta, req, sl, final)
699			},
700			ToolWiringHook:          s.toolWiringHook(),
701			PromptAssertionHook:     s.promptAssertionHook(),
702			CompactionAssertionHook: s.compactionAssertionHook(),
703			ObserveTokenUsage:       s.observeTokenUsage,
704		})
705	}
