726	func nativeRouteCandidates(in []RouteCandidate) []serviceimpl.NativeRouteCandidate {
727		if len(in) == 0 {
728			return nil
729		}
730		out := make([]serviceimpl.NativeRouteCandidate, len(in))
731		for i, candidate := range in {
732			out[i] = serviceimpl.NativeRouteCandidate{
733				Provider:       candidate.Provider,
734				Endpoint:       candidate.Endpoint,
735				ServerInstance: candidate.ServerInstance,
736				Model:          candidate.Model,
737				Eligible:       candidate.Eligible,
738			}
739		}
740		return out
741	}
