743	func newServiceCompactor(req ServiceExecuteRequest, model string) agentcore.Compactor {
744		cfg := compaction.DefaultConfig()
745		if req.CompactionContextWindow > 0 {
746			cfg.ContextWindow = req.CompactionContextWindow
747			if cfg.ReserveTokens >= cfg.ContextWindow {
748				cfg.ReserveTokens = 0
749			}
750			if cfg.KeepRecentTokens > cfg.ContextWindow {
751				cfg.KeepRecentTokens = cfg.ContextWindow / 2
752			}
753		}
754		if req.CompactionReserveTokens > 0 {
755			cfg.ReserveTokens = req.CompactionReserveTokens
756		}
757		if catalog, err := modelcatalog.Default(); err == nil && catalog != nil && model != "" && req.CompactionContextWindow <= 0 {
758			if contextWindow := catalog.ContextWindowForModel(model); contextWindow > 0 {
759				cfg.ContextWindow = contextWindow
760			}
761		}
762		return compaction.NewCompactor(cfg)
763	}
