765	// runSubprocess delegates to a Runner under internal/harnesses/<name>. It
766	// re-uses the wall-clock-bounded ctx so PTY/orphan reaping is automatic
767	// when our ctx (which already carries the request Timeout) cancels.
768	func (s *service) runSubprocess(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string, runner harnesses.Harness) {
769		progress := newSubprocessProgressState(req)
770		serviceimpl.RunSubprocess(ctx, serviceimpl.SubprocessRequest{
771			Prompt:        req.Prompt,
772			SystemPrompt:  req.SystemPrompt,
773			WorkDir:       req.WorkDir,
774			Permissions:   req.Permissions,
775			Temperature:   req.Temperature,
776			Seed:          req.Seed,
777			Reasoning:     effectiveReasoning(req.Reasoning),
778			Timeout:       req.Timeout,
779			IdleTimeout:   req.IdleTimeout,
780			SessionLogDir: req.SessionLogDir,
781			Metadata:      meta,
782			Decision: serviceimpl.ExecuteRunnerDecision{
783				Harness:  decision.Harness,
784				Provider: decision.Provider,
785				Model:    decision.Model,
786			},
787			Started:        start,
788			SessionLogPath: sessionLogPath(sl),
789		}, runner, serviceimpl.SubprocessCallbacks{
790			BeforeExecute: func() {
791				emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
792			},
793			BeforeFinal: func(final harnesses.FinalData) {
794			},
795			ObserveEvent: func(ev harnesses.Event) harnesses.Event {
796				ev = progress.annotateToolResultDuration(ev)
797				if payload, ok := progress.noteEvent(ev); ok && ev.Type != harnesses.EventTypeProgress {
798					emitProgress(out, seq, sl, sessionID, meta, payload)
799				}
800				if ev.Type == harnesses.EventTypeFinal {
801					if payload, ok := progress.noteFinal(ev); ok {
802						emitProgress(out, seq, sl, sessionID, meta, payload)
803					}
804				}
805				return ev
806			},
807			EmitEvent: func(ev harnesses.Event) bool {
808				ev.Sequence = seq.Add(1) - 1
809				select {
810				case out <- ev:
811					return true
812				case <-ctx.Done():
813					return false
814				}
815			},
816			Finalize: func(final harnesses.FinalData) {
817				finalizeAndEmit(out, seq, meta, req, sl, final)
818			},
819			WriteEnd: func(finalMeta map[string]string, final harnesses.FinalData) {
820				sl.writeEnd(req, finalMeta, final)
821			},
822		})
823	}
824	
825	func sessionLogPath(sl *serviceSessionLog) string {
826		if sl == nil {
827			return ""
828		}
829		return sl.path
830	}
831	
832	// emitFinal wraps a FinalData into a ServiceEvent and writes it to out.
833	// The channel close happens in the caller via defer; this only writes the
834	// terminator event.
835	func emitFinal(out chan<- ServiceEvent, seq *atomic.Int64, meta map[string]string, final harnesses.FinalData) {
836		raw, err := json.Marshal(final)
837		if err != nil {
838			raw = []byte(`{"status":"failed","error":"marshal final"}`)
839		}
840		ev := harnesses.Event{
841			Type:     harnesses.EventTypeFinal,
842			Sequence: seq.Add(1) - 1,
843			Time:     time.Now().UTC(),
844			Metadata: meta,
845			Data:     raw,
846		}
847		select {
848		case out <- ev:
849		case <-time.After(time.Second):
850		}
851	}
852	
853	// emitFatalFinal is used when Execute itself can't construct a route. It
854	// writes a single failed final event then closes the channel — used for
855	// the "no consumer goroutine" path so we still satisfy the channel
856	// contract.
857	func emitFatalFinal(out chan<- ServiceEvent, meta map[string]string, status, errMsg string) {
858		defer close(out)
859		final := harnesses.FinalData{Status: status, Error: errMsg}
860		raw, _ := json.Marshal(final)
861		ev := harnesses.Event{
862			Type:     harnesses.EventTypeFinal,
863			Sequence: 0,
864			Time:     time.Now().UTC(),
865			Metadata: meta,
866			Data:     raw,
867		}
868		select {
869		case out <- ev:
870		case <-time.After(time.Second):
871		}
872	}
873	
874	// emitJSON marshals payload and writes a typed event to out.
875	func emitJSON(out chan<- ServiceEvent, seq *atomic.Int64, t harnesses.EventType, meta map[string]string, payload any) {
876		raw, err := json.Marshal(payload)
877		if err != nil {
878			return
879		}
880		ev := harnesses.Event{
881			Type:     t,
882			Sequence: seq.Add(1) - 1,
883			Time:     time.Now().UTC(),
884			Metadata: meta,
885			Data:     raw,
886		}
887		select {
888		case out <- ev:
889		case <-time.After(time.Second):
890		}
891	}
892	
893	// emitJSONRaw is the typed-payload variant used inside the loop callback.
894	func emitJSONRaw(out chan<- ServiceEvent, seq *atomic.Int64, t harnesses.EventType, meta map[string]string, payload any) {
895		emitJSON(out, seq, t, meta, payload)
896	}
897	
898	// finalizeAndEmit stamps the service-owned session-log path onto final,
899	// records the terminal session.end event, and forwards the final to the
900	// public event stream. Every terminal emit path in runExecute funnels
901	// through this helper so the session log and the event channel stay in
902	// lock-step (CONTRACT-003).
903	//
904	// finalizeAndEmit also performs the CONTRACT-003 echo of top-level Role
905	// and CorrelationID into the final event Metadata (top-level wins over
906	// any caller-supplied Metadata entry under the same reserved key) and
907	// stamps RoutingActual.Power from the catalog projection of the
908	// actually-dispatched Model. When the caller set both top-level
909	// Role/CorrelationID and the same reserved Metadata key, a
910	// MetadataKeyCollision warning is appended to final.Warnings.
911	func finalizeAndEmit(out chan<- ServiceEvent, seq *atomic.Int64, meta map[string]string, req ServiceExecuteRequest, sl *serviceSessionLog, final harnesses.FinalData) {
912		if sl != nil && sl.path != "" {
913			final.SessionLogPath = sl.path
914		}
915		// Stamp catalog power onto the actually-dispatched RoutingActual.
916		// final.RoutingActual is set by the caller (one per terminal path);
917		// when nil we leave it nil to avoid synthesizing routing evidence.
918		if final.RoutingActual != nil && final.RoutingActual.Power == 0 {
919			final.RoutingActual.Power = catalogPowerForModel(serviceRoutingCatalog(), final.RoutingActual.Model)
920		}
921		// Detect reserved metadata-key collisions and append a warning so the
922		// caller learns when their caller-supplied Metadata entries were
923		// overridden by the top-level Role / CorrelationID fields.
924		if collisions := metadataReservedKeyCollisions(req.Metadata, req.Role, req.CorrelationID); len(collisions) > 0 {
925			final.Warnings = append(final.Warnings, harnesses.FinalWarning{
926				Code:    MetadataWarningCodeKeyCollision,
927				Message: metadataKeyCollisionMessage(collisions),
928			})
929		}
930		// Echo Role + CorrelationID onto the final event Metadata.
931		finalMeta := metaWithRoleAndCorrelation(meta, req.Role, req.CorrelationID)
932		if sl != nil {
933			if ovr := sl.override; ovr != nil && !ovr.emitted.Load() {
934				sl.writeOverrideEvent(ServiceEventTypeOverride, ovr.payload)
935			}
936			sl.writeEnd(req, finalMeta, final)
937		}
938		emitFinal(out, seq, finalMeta, final)
939	}
