370	func readFinalEvent(t *testing.T, ch <-chan ServiceEvent, timeout time.Duration) ServiceFinalData {
371		t.Helper()
372		deadline := time.NewTimer(timeout)
373		defer deadline.Stop()
374		for {
375			select {
376			case ev, ok := <-ch:
377				if !ok {
378					t.Fatal("Execute channel closed without final event")
379				}
380				if ev.Type != "final" {
381					continue
382				}
383				var payload ServiceFinalData
384				if err := json.Unmarshal(ev.Data, &payload); err != nil {
385					t.Fatalf("unmarshal final event: %v", err)
386				}
387				return payload
388			case <-deadline.C:
389				t.Fatalf("timed out after %s waiting for final event", timeout)
390				return ServiceFinalData{}
391			}
392		}
393	}
