55	// RunWithConfigViaService dispatches a single agent invocation through the
56	// agent service. It takes a sealed ResolvedConfig (durable knobs) and an
57	// AgentRunRuntime (per-invocation plumbing/intent), and is the SD-024
58	// successor to the retired RunViaService/RunViaServiceWith entry points.
59	//
60	// The virtual and script harnesses route through a DDx-owned Runner path,
61	// not the upstream service. These are not "carve-outs pending migration" —
62	// they are different products from upstream's same-named stubs. DDx's
63	// virtual is a content-addressed record/replay dictionary keyed by
64	// PromptHash; upstream's is a unit-test stub where callers stuff
65	// virtual.response into Metadata. DDx's script reads a filesystem directive
66	// file; upstream does not model this at all.
67	func RunWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
68		if ctx == nil {
69			ctx = context.Background()
70		}
71	
72		harness := rcfg.Passthrough().Harness
73	
74		effectivePerms := runtime.PermissionsOverride
75		if effectivePerms == "" {
76			effectivePerms = rcfg.Permissions()
77		}
78		if err := ValidateReadOnlyReviewerDispatch(harness, effectivePerms); err != nil {
79			return nil, err
80		}
81	
82		if harness == "virtual" || harness == "script" {
83			sessionLogDir := runtime.SessionLogDirOverride
84			if sessionLogDir == "" {
85				sessionLogDir = rcfg.SessionLogDir()
86			}
87			cfg := Config{SessionLogDir: ResolveLogDir(workDir, "")}
88			r := NewRunner(cfg)
89			r.WorkDir = workDir
90			return r.runInternal(RunArgs{
91				Context:       ctx,
92				Harness:       rcfg.Harness(),
93				Prompt:        runtime.Prompt,
94				PromptFile:    runtime.PromptFile,
95				PromptSource:  runtime.PromptSource,
96				Correlation:   runtime.Correlation,
97				Model:         rcfg.Model(),
98				Provider:      rcfg.Provider(),
99				ModelRef:      rcfg.ModelRef(),
100				Effort:        rcfg.Effort(),
101				Timeout:       rcfg.Timeout(),
102				WallClock:     rcfg.WallClock(),
103				WorkDir:       runtime.WorkDir,
104				Permissions:   rcfg.Permissions(),
105				SessionLogDir: sessionLogDir,
106				Env:           runtime.Env,
107			})
108		}
109	
110		factory := serviceRunFactory
111		if factory == nil {
112			factory = NewServiceFromWorkDir
113		}
114		svc, err := factory(workDir)
115		if err != nil {
116			return nil, fmt.Errorf("agent: build service: %w", err)
117		}
118		return executeOnService(ctx, svc, workDir, rcfg, runtime)
119	}
